INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('6e652351-8445-42ef-91dd-ddbf6f9320b4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Ultra course view$q$, $q$A modern, mobile-responsive course interface that Anthology has positioned as the successor to the older Original view.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Gradebook and assessment tools$q$, $q$Rubric-based grading, online tests and assignments, and grade analytics for tracking student performance.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Blackboard Collaborate$q$, $q$Built-in virtual classroom and video conferencing tool integrated directly into courses.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Discussion boards and journals$q$, $q$Asynchronous discussion and reflection tools for student engagement outside live class time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Blackboard Ally integration$q$, $q$Automated accessibility checks on course content with alternative-format generation for students.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Mobile app$q$, $q$Native iOS and Android apps for students and instructors to access courses, grades, and notifications on the go.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$LTI and API integrations$q$, $q$Standards-based LTI support and a Building Blocks/REST API framework for connecting publisher content, SIS data, and third-party tools.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Analytics and reporting$q$, $q$Course- and institution-level dashboards for monitoring student engagement and academic performance.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Content organization and adaptive release$q$, $q$Modules, folders, and rule-based release of course content tailored to student progress.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$AI-assisted course tools$q$, $q$Generative AI features introduced by Anthology to help instructors with course design and content tasks.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Mature, deep feature set refined over more than two decades of higher-education use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Strong built-in accessibility support through Blackboard Ally integration$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Broad integration ecosystem via LTI, APIs, and publisher/SIS connections$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Scales to large, multi-campus institutions with complex administrative needs$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Built-in virtual classroom (Collaborate) reduces reliance on separate video tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Pricing isn't published and typically requires a lengthy institutional procurement process$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$The legacy Original course view can feel dated next to newer, cloud-native LMS competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Learning curve for instructors and admins unfamiliar with the platform can be steep$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Implementation and onboarding for large institutions can be slow and resource-intensive$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Not designed for individual educators or small training providers who need self-service, low-cost access$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$What is Blackboard Learn used for?$q$, $q$Blackboard Learn is a learning management system used by schools and universities to deliver course content, manage assignments and grading, host discussions, and track student performance online.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Is Blackboard Learn free to use?$q$, $q$No. Blackboard Learn is sold to institutions under custom, quote-based licensing rather than a public free or self-service plan; individual students and instructors access it through their institution's account.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Who owns Blackboard Learn now?$q$, $q$Blackboard Learn is owned and developed by Anthology, following the 2021 merger of Blackboard and Anthology.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$What's the difference between Blackboard Ultra and Original course view?$q$, $q$Ultra is Anthology's newer, mobile-responsive interface for Blackboard Learn, while Original is the platform's older, more traditional course view; many institutions are migrating from Original to Ultra.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Does Blackboard Learn have a mobile app?$q$, $q$Yes, Blackboard offers a mobile app for iOS and Android that lets students and instructors check grades, submit work, and receive course notifications.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Higher education course delivery$q$, $q$Universities and colleges use Blackboard Learn as their primary platform for hosting course content, assignments, and grades across departments.$q$, $q$Universities and colleges$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$K-12 blended and online learning$q$, $q$School districts deploy Blackboard Learn to support blended or fully online instruction for students.$q$, $q$K-12 school districts$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Multi-campus academic administration$q$, $q$Large, multi-campus institutions use Blackboard Learn to standardize course delivery, integrations, and reporting across many programs.$q$, $q$IT and academic administrators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Accessible course content delivery$q$, $q$Institutions with accessibility compliance requirements use Blackboard Learn alongside Blackboard Ally to check and remediate course materials.$q$, $q$Disability services and compliance teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$SaaS (Cloud)$q$, $q$Custom quote$q$, $q$annual$q$, $q$["Fully hosted and managed by Anthology","Automatic platform updates","Ultra course view included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Managed Hosting$q$, $q$Custom quote$q$, $q$annual$q$, $q$["Hosted by Anthology","Institution controls upgrade timing","Dedicated environment"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$Self-Hosted$q$, $q$Custom quote$q$, $q$annual$q$, $q$["Deployed on the institution's own infrastructure","Full administrative control","Institution manages upgrades and maintenance"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Blackboard Learn is a long-standing enterprise learning management system (LMS) built for colleges, universities, and school districts to deliver, organize, and assess coursework online. Founded in 1997 and headquartered in Reston, Virginia, Blackboard has been one of the defining names in higher-education technology for over two decades, predating most of today's cloud-native LMS competitors.$q$, $q$The company merged with Anthology in 2021, and Blackboard Learn is now developed and sold under the Anthology brand alongside other Anthology education products (such as Blackboard Ally for accessibility and Blackboard Collaborate for virtual classrooms). Despite the corporate change, the Blackboard Learn product name and its large installed base of institutional customers have continued.$q$, $q$Blackboard Learn is offered in an older interface known as the 'Original' course view and a newer, mobile-responsive 'Ultra' course view, which Anthology has been pushing institutions to migrate to. It's sold as an institution-wide platform rather than a per-user consumer product, with implementation typically handled through a sales and procurement process rather than self-service signup.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$who-its-for$q$, $q$Who Blackboard Learn Is For$q$, 2, ARRAY[$q$Blackboard Learn is built for higher-education institutions — universities, community colleges, and multi-campus systems — that need a single LMS to standardize course delivery, grading, and reporting across many departments and thousands of students and instructors. It also serves K-12 school districts running online or blended learning programs.$q$, $q$It suits IT and academic administrators who need centralized control: integration with student information systems (SIS), single sign-on, granular permissions, and institution-wide analytics. Because of its accessibility tooling (via Blackboard Ally) and long compliance track record, it's also a common choice for institutions with strict accessibility and regulatory obligations.$q$, $q$Instructors who teach within an established institutional deployment — rather than choosing their own tools — are the typical day-to-day users, using Blackboard Learn for content delivery, assignments, discussion boards, and grading within a course shell configured by their institution.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Individual educators, small training providers, or standalone course creators who need a lightweight, self-service tool will generally find Blackboard Learn oversized and inaccessible — it isn't sold as a small-team or individual subscription, and there's no public self-signup pricing.$q$, $q$Institutions that prioritize a fast, modern setup experience with minimal IT involvement may prefer newer, cloud-native LMS platforms; Blackboard's Original course view in particular can feel dated, and full migration to the Ultra experience takes deliberate planning.$q$, $q$Organizations wary of long procurement cycles and custom contract negotiations should also be cautious, since pricing and implementation timelines are institution-specific rather than transparent or instant.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Blackboard Learn's core toolset covers the full course lifecycle: content authoring and organization (modules, folders, adaptive release rules), a gradebook with rubrics and analytics, assignments and tests, and discussion boards and journals for asynchronous engagement. The Ultra course view offers a simplified, mobile-responsive interface layered on top of this functionality.$q$, $q$It integrates tightly with other Anthology products, notably Blackboard Collaborate for built-in video conferencing and virtual classrooms, and Blackboard Ally, which automatically checks course content for accessibility issues and generates alternative formats for students. Standards-based integrations (LTI) and a Building Blocks/REST API framework let institutions connect publisher content, plagiarism-detection tools, and SIS data.$q$, $q$More recently, Anthology has introduced generative AI–assisted capabilities into the Blackboard/Anthology ecosystem, such as AI-assisted course design support, alongside its established reporting and analytics dashboards for tracking student engagement and performance at the course and institution level.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', $q$the-blackboard-learn-experience$q$, $q$The Blackboard Learn Experience$q$, 2, ARRAY[$q$Day to day, Blackboard Learn functions as the digital front door for a course: students log in to see announcements, content modules, upcoming assignments, and grades, while instructors manage all of that through an admin-configured course shell. The experience varies noticeably depending on whether an institution has adopted the Ultra course view or is still running the Original interface.$q$, $q$A dedicated Blackboard mobile app (available on iOS and Android) lets students check grades, submit assignments, and receive notifications from their phones, which has become a standard expectation for campus LMS platforms.$q$, $q$Because Blackboard Learn is deployed and configured centrally by each institution — including branding, integrations, and enabled tools — the actual look, feel, and feature set a given student or instructor experiences can differ meaningfully from one school to the next, even though the underlying platform is the same.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
