INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5f612c37-64e2-4aeb-a2a0-9b6d63df09b4', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$WebContainers in-browser runtime$q$, $q$A full Node.js development environment runs directly inside the browser tab, so there's nothing to install locally to build, run, or preview a project.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$AI chat-driven app generation$q$, $q$Describe an app in plain English and Bolt scaffolds the project structure, installs dependencies, and starts a working dev server automatically.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Live, editable code and file explorer$q$, $q$Every file Bolt generates is visible and directly editable in the browser, so users aren't limited to what the AI produces on its own.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Instant live preview$q$, $q$Changes made by the AI or by hand appear in a real-time preview pane next to the chat, without manual rebuilds or refreshes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$One-click deployment with custom domains$q$, $q$Projects can be published to a live URL in one click, with custom domain support and branding removal on paid plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Supabase integration$q$, $q$Add authentication, a Postgres database, and storage to a project through built-in Supabase support instead of manual backend setup.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Stripe integration$q$, $q$Native Stripe support lets projects handle one-time payments and subscription billing without custom payment-integration work.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$GitHub import and export$q$, $q$Existing repositories can be imported as a starting point, and Bolt projects can be pushed back out to GitHub.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Figma design import$q$, $q$Figma files can be imported and converted into working front-end components that preserve layout and styling.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Expo integration for mobile$q$, $q$Mobile apps for iOS and Android can be built from the same browser-based project using Expo, including QR-code preview.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Extremely fast path from idea to a working, deployable app with no local setup required.$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Runs entirely in the browser via WebContainers, so anyone with a laptop and internet connection can build.$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$The free plan is genuinely usable for small projects, not just a limited demo.$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Built-in integrations with Netlify, Supabase, and Stripe shorten the path from prototype to a live, functioning product.$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Generated code remains fully visible and editable, so developers aren't locked out of the underlying codebase.$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Token-based pricing can get expensive quickly on larger or more complex projects.$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$The browser-based sandbox has some limits compared to a full local development environment.$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$AI-generated code still needs review and debugging before it's production-ready.$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Free-tier daily and monthly token caps can be exhausted quickly with iterative prompting.$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Best suited to JavaScript/TypeScript web stacks, making it less useful outside that ecosystem.$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$What is Bolt.new?$q$, $q$Bolt.new is an AI-powered, browser-based tool from StackBlitz that generates, edits, and deploys full-stack web applications from natural-language prompts, using in-browser WebContainers technology instead of a local dev setup.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Is Bolt.new free to use?$q$, $q$Yes. Bolt.new has a free plan with a monthly and daily token allowance that's usable for small projects; paid Pro, Teams, and Enterprise plans remove limits and add features like custom domains and higher token allowances.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$What is WebContainers technology and why does it matter?$q$, $q$WebContainers is StackBlitz's own technology for running a full Node.js environment, including a package manager and file system, directly inside the browser, which is what lets Bolt.new build and run projects without any local installation.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Can I access and export the code Bolt.new generates?$q$, $q$Yes. All generated files are visible and editable in the browser, and projects can be imported from or exported to GitHub, so users aren't limited to Bolt's hosted environment.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Who makes Bolt.new?$q$, $q$Bolt.new is built and operated by StackBlitz, a company known for browser-based development environments, founded by Eric Simons and Albert Pai.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Rapid MVP prototyping$q$, $q$Turn a product idea into a working app with authentication and a database in hours instead of weeks, to validate a concept quickly.$q$, $q$Founders and indie hackers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Figma-to-code conversion$q$, $q$Import an existing design file and convert it into working front-end code that preserves layout and styling.$q$, $q$Designers and product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Internal tools and dashboards$q$, $q$Build lightweight internal apps and admin dashboards without dedicating engineering time to routine CRUD tooling.$q$, $q$Small teams and operations staff$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Learning full-stack development$q$, $q$Generate a working project and inspect the real code behind it as a way to learn how a full-stack app is structured.$q$, $q$Students and hobbyist coders$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Free$q$, $q$$0$q$, NULL, $q$["300K daily token limit","1M monthly tokens","Public and private projects","10MB file uploads","Website hosting","Bolt branding included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Pro$q$, $q$$25/month$q$, $q$monthly$q$, $q$["No daily token limit","10M+ monthly tokens with rollover","Private site sharing","100MB file uploads","Custom domain support","No Bolt branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Teams$q$, $q$$30/member/month$q$, $q$monthly$q$, $q$["Everything in Pro","Centralized billing","Team-level access management","Admin controls and user provisioning","Private NPM registries"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["SSO and audit logs","Dedicated account manager","24/7 priority support","Custom workflows and integrations","Enterprise training"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Bolt.new is an AI-powered, browser-based platform built by StackBlitz that lets people build, edit, and deploy full-stack web applications purely from natural-language prompts. Launched in 2024, it quickly became one of the most talked-about products in the new wave of AI app builders, alongside tools like v0 and Lovable. What sets Bolt.new apart technically is StackBlitz's own WebContainers technology, which runs a full Node.js environment directly inside the browser tab — no local installation, terminal, or IDE required to go from a description of an app to a running, editable project.$q$, $q$The typical workflow starts with a single prompt describing the app you want, such as a task manager with login and a Kanban board. Bolt scaffolds the project, installs the necessary npm packages, starts a dev server, and shows a live preview next to a chat panel — all within seconds, entirely client-side. From there, users refine the app conversationally, asking Bolt to change layouts, add features, or fix bugs, while also being able to open the generated files directly and hand-edit code. When the app is ready, it can be deployed with one click to a live URL, with custom domain support on paid plans.$q$, $q$Bolt.new has since expanded well beyond a single-shot app generator: it now supports importing existing GitHub repositories and Figma designs as starting points, native Supabase integration for auth and databases, Stripe integration for payments, and Expo-based mobile app generation from the same browser workflow — positioning it as a fairly complete, if still AI-driven, path from idea to shipped product.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$who-its-for$q$, $q$Who Bolt.new Is For$q$, 2, ARRAY[$q$Bolt.new is aimed squarely at people who want to go from an idea to a working, deployable product with minimal friction. Non-technical founders and indie hackers use it to validate ideas quickly, spinning up a functional MVP — complete with a database and login — in an afternoon rather than weeks. Because everything runs in the browser, it also works well for anyone without a fully set-up local dev machine.$q$, $q$Designers and product people benefit from Bolt's ability to import a Figma file and turn it into working front-end code, letting them see a static design come alive without waiting on a developer. Developers themselves also use Bolt as a fast scaffolding tool — spinning up boilerplate, prototypes, or internal tools, then taking over the generated codebase, which remains fully visible and exportable, to refine by hand.$q$, $q$Small teams and solo operators building internal tools, client demos, landing pages, or simple SaaS prototypes are a natural fit, especially given the built-in Stripe and Supabase integrations that remove a lot of the usual backend setup work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Bolt.new is less suited to teams building large, complex, or highly regulated applications that need a fully controlled local or CI environment, custom infrastructure, or non-JavaScript backend stacks — WebContainers run a Node.js/TypeScript environment in-browser, so projects requiring other languages or heavy native system dependencies won't fit neatly into that model.$q$, $q$Engineers who want granular control over their toolchain, package versions, or deployment pipeline from day one may find the AI-first, prompt-driven workflow gets in the way rather than helping, especially once a project grows large and token consumption, and cost, rises with codebase complexity. Teams with strict security, compliance, or on-premises requirements should also evaluate the Enterprise tier carefully before committing, since default plans run through Bolt's own hosted infrastructure.$q$, $q$Finally, anyone expecting production-ready, audit-clean code straight out of the box should temper expectations — like all current AI code generators, Bolt's output still benefits from manual review, testing, and hardening before shipping anything business-critical.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Bolt.new pairs a chat interface with a live, in-browser dev environment: prompts on one side, a running preview and file tree on the other, so every change the AI makes is immediately visible and directly editable. This is powered by WebContainers, letting a real Node.js server, package manager, and file system run without any server round-trip.$q$, $q$Beyond generation, Bolt has built out a set of integrations aimed at making it a genuine product-building tool rather than just a demo generator: one-click deployment with custom domains on paid plans, Supabase for database, auth, and storage, Stripe for payments and subscriptions, GitHub import and export for working with existing repos, Figma import for design-to-code, and Expo integration for building mobile apps from the same project.$q$, $q$Paid plans add team collaboration features — shared billing, admin controls, private project sharing, and design-system-aware prompting for Teams — plus higher and rolling-over token allowances so usage doesn't reset to zero every month.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', $q$the-experience$q$, $q$The Bolt.new Experience$q$, 2, ARRAY[$q$Using Bolt.new feels less like configuring a tool and more like having a conversation with a developer who can also type extremely fast. The first response to a prompt — a scaffolded, running app — typically appears within seconds, which is a large part of why the product spread so quickly through social media demos and hackathons after its 2024 launch.$q$, $q$The day-to-day loop is iterative: describe a change, watch Bolt apply it and the preview update, then either keep prompting or dive into the code editor to make a manual tweak. That mix of natural-language control and full code access is what distinguishes Bolt.new from purely no-code builders — it doesn't hide the underlying project from you, which matters once you outgrow prompting alone.$q$, $q$The trade-off is that the experience is tightly coupled to token consumption: heavier prompting, larger codebases, and more AI-driven debugging cycles all draw down the monthly allowance, so power users on bigger projects will want to keep an eye on usage as the project scales.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e82c60dd-a99b-47e5-b59b-e27db707e04e', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
