INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Visual drag-and-drop pipeline$q$, $q$Kanban-style candidate pipeline lets recruiters and hiring managers move applicants through stages with a simple drag of the mouse.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Job board distribution$q$, $q$Post open roles to 50+ free and paid job boards from a single posting, plus a customizable branded careers page.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Resume parsing$q$, $q$Automatically extracts candidate details from resumes to populate applicant profiles and speed up screening.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Interview self-scheduling and video$q$, $q$Candidates can self-book interview slots, and built-in live video supports remote interviewing without extra tools.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Scorecards and interview guides$q$, $q$Customizable, structured evaluation forms help hiring teams standardize feedback across interviewers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Automated reference checking$q$, $q$Sends and collects structured reference check responses automatically as candidates progress through the pipeline.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$e-Signatures for offers$q$, $q$Candidates can review and sign offer letters electronically within the platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Analytics and reporting$q$, $q$Real-time dashboards track hiring pipeline metrics, time-to-fill, and source effectiveness.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Mobile apps$q$, $q$Native iOS and Android apps let hiring teams review candidates and manage pipelines on the go.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$HRIS integrations$q$, $q$Higher-tier plans connect Breezy to HRIS systems to pass hired-candidate data into onboarding and HR workflows.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Genuinely free plan (Bootstrap) with unlimited users and candidates for one open position$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Intuitive, visual drag-and-drop pipeline that's easy for non-recruiters to use$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Flat, unlimited-user pricing rather than per-seat fees, which suits teams with many hiring stakeholders$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Broad one-click distribution to 50+ job boards and a built-in branded careers page$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Built-in interview self-scheduling and live video reduce the need for separate scheduling tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Free plan is capped at a single active position and retains candidate data for only 30 days$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Advanced features like HRIS integration, API access, custom roles, and advanced reporting are locked to the top Business or custom Pro tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Pricing rises noticeably from tier to tier, and add-ons (SMS, onboarding, AI credits) cost extra on top of the subscription$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Less configurable and less compliance-focused than enterprise ATS platforms for complex, high-volume, multi-region hiring$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Not designed for very large organizations running many simultaneous, highly customized recruiting workflows$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Does Breezy HR have a free plan?$q$, $q$Yes. The Bootstrap plan is free indefinitely and includes unlimited users and candidates, but it's limited to one active open position and 30-day candidate data retention.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$How much does Breezy HR cost?$q$, $q$Paid plans range from roughly $157/month for Startup up to $439/month for Business when billed annually, with a custom-quoted Pro plan above that; monthly (non-annual) billing costs more per month.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Does Breezy HR post to job boards?$q$, $q$Yes, Breezy distributes job postings to 50+ free and paid job boards from a single listing and includes a customizable branded careers page.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Does Breezy HR support video interviews and scheduling?$q$, $q$Yes, paid plans include candidate self-scheduling and built-in live video interviewing, removing the need for separate scheduling software.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Is there a Breezy HR mobile app?$q$, $q$Yes, Breezy offers native mobile apps for both iOS and Android so hiring teams can manage pipelines and review candidates remotely.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$First hires for a small business$q$, $q$A founder or small team hiring their first employees uses the free Bootstrap plan to post a role, collect applicants, and manage the process without spreadsheets.$q$, $q$Small business owners and founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Scaling a growing startup's hiring$q$, $q$A startup moving from occasional to continuous hiring upgrades to Startup or Growth to unlock unlimited positions, automation, and structured interview scorecards.$q$, $q$Startup HR and talent teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Managing multiple simultaneous openings$q$, $q$A staffing agency or multi-department company runs several custom pipelines at once, tracking each role's candidates separately in one shared account.$q$, $q$Recruiting agencies and multi-department HR teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Standardizing structured interviews$q$, $q$An HR team uses customizable scorecards and interview guides across hiring managers to reduce bias and keep evaluation criteria consistent.$q$, $q$HR generalists and hiring managers$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Bootstrap (Free)$q$, $q$$0$q$, NULL, $q$["1 active position or talent pool","Unlimited users and candidates","Branded career site","Distribution to 50+ job boards","GDPR compliance tools","Resume parsing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Startup$q$, $q$From ~$157/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Unlimited open positions","Email and calendar integration","Interview self-scheduling and live video","Mobile apps (iOS & Android)","Real-time analytics","Slack integration"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Growth$q$, $q$From ~$273/month (billed annually)$q$, $q$monthly or annual$q$, $q$["Multiple custom recruiting pipelines","Automated reference checking","Customizable scorecards and interview guides","e-Signatures for offers","Employee referral portal"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$Business$q$, $q$From ~$439/month (billed annually)$q$, $q$monthly or annual$q$, $q$["HRIS integrations","Offer and job approval workflows","Custom roles and permissions","Candidate nurture campaigns","Assessment integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Breezy HR is a cloud-based applicant tracking system (ATS) and recruiting platform designed to make hiring feel less like paperwork and more like a visual, drag-and-drop workflow. Instead of long candidate lists and spreadsheet-style tracking, Breezy organizes applicants into a Kanban-style pipeline, letting recruiters and hiring managers move candidates from 'New Applicant' through 'Interview' to 'Offer' with a simple drag of the mouse.$q$, $q$The platform bundles the core stages of recruiting into one place: posting jobs to dozens of job boards at once, building a branded careers page, sourcing and screening candidates, scheduling interviews (including self-scheduling and live video), and collecting team feedback through scorecards. It is aimed squarely at small and mid-sized businesses that want ATS-grade organization without the complexity or per-seat cost structure of enterprise recruiting suites.$q$, $q$A distinguishing feature is Breezy's permanently free 'Bootstrap' tier, which allows unlimited users and candidates for a single open position — a rarity in the ATS category, where most competitors gate access behind a trial or paid seat. Paid tiers scale up through Startup, Growth, and Business plans, unlocking unlimited job postings, automation, e-signatures, HRIS integrations, and more advanced compliance and reporting tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$who-is-for$q$, $q$Who Breezy HR Is For$q$, 2, ARRAY[$q$Breezy HR is best suited to small businesses and growing startups that hire occasionally to regularly but don't have a dedicated, large in-house recruiting operation. Its flat, unlimited-user pricing model (rather than per-recruiter seat fees) makes it attractive for teams where multiple hiring managers, interviewers, and executives need pipeline visibility without the company having to pay per login.$q$, $q$It also suits businesses that value ease of use and quick setup over deep configurability. Founders hiring their first few employees, HR generalists wearing the recruiting hat alongside other duties, and small agencies or staffing firms managing several open roles at once tend to get up and running with Breezy in a day rather than weeks, thanks to its visual pipeline and largely self-explanatory interface.$q$, $q$Companies that need broad job board distribution and simple interview scheduling — without building a full talent-acquisition tech stack — are a strong fit, as are teams that want a genuinely free option while they're only hiring for one role at a time.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large enterprises with complex, multi-region hiring compliance needs, deep HRIS/ERP integration requirements, or high-volume recruiting across dozens of simultaneous requisitions may find Breezy's feature depth thinner than category leaders built specifically for enterprise talent acquisition, such as Greenhouse, Workday, or Lever, particularly around advanced reporting, custom workflow logic, and API-driven integrations.$q$, $q$Organizations that need everything unlocked immediately should also be cautious: several of Breezy's more advanced capabilities — HRIS integrations, offer/job approval workflows, custom roles and permissions, API access, and advanced reporting — are reserved for the top Business tier or the custom-quoted Pro plan, and add-ons like SMS messaging, onboarding, and AI credits carry additional cost on top of the base subscription.$q$, $q$Teams hiring for more than one role who expect to stay on the free plan will also be limited immediately, since Bootstrap allows only a single active position and retains candidate data for just 30 days — fine for testing the product, but not a long-term solution for active multi-role recruiting.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At the center of Breezy is its visual, drag-and-drop candidate pipeline, which can be customized per position and shared with hiring managers for quick collaborative decision-making. Around that pipeline, Breezy layers one-click distribution to more than 50 free and paid job boards, a customizable branded careers page, and resume parsing to help populate candidate profiles automatically.$q$, $q$Interview logistics are handled through built-in scheduling tools, including candidate self-scheduling and live video interviews, paired with customizable scorecards and interview guides so teams can standardize how they evaluate applicants. Paid plans add automated reference checking, e-signatures for offer letters, an employee referral portal, and a messenger tool for engaging passive candidates.$q$, $q$On the operations side, Breezy offers email and calendar integration, real-time analytics and reporting, mobile apps for iOS and Android, and — on higher tiers — HRIS integrations, custom roles and permissions, and AI-assisted tools (branded as Breezy Intelligence) for tasks like candidate matching, sold as an add-on credit pack.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7cac63e1-ade1-4e49-9c9c-3d85ed715d3a', $q$experience$q$, $q$The Breezy HR Experience$q$, 2, ARRAY[$q$Users and reviewers consistently describe Breezy's interface as clean, modern, and fast to learn, with the visual pipeline in particular praised for making recruiting status easy to see at a glance for anyone on the hiring team, not just the recruiter running the account. Onboarding tends to be lightweight, and the free tier gives prospective customers a genuine, no-time-limit way to try the core workflow before paying anything.$q$, $q$Where the experience gets more mixed is around pricing transitions and add-on costs as teams grow: moving from the free plan to paid tiers, and later from Startup toward Growth or Business, unlocks meaningfully more functionality but also increases the monthly bill noticeably tier to tier, and several extras (SMS, onboarding module, AI credits) sit outside the base subscription price.$q$, $q$Overall, Breezy HR delivers on its promise of making applicant tracking approachable and visual rather than spreadsheet-like, and it remains a popular choice among small businesses precisely because it trades some enterprise-grade depth for simplicity, flat unlimited-user pricing, and a low barrier to entry.$q$]::text[], 4);
