INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Email Campaign Builder$q$, $q$Drag-and-drop editor with pre-built templates for designing and sending newsletters and marketing campaigns.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Marketing Automation$q$, $q$Visual workflow builder for triggering emails and SMS based on subscriber behavior, such as signups, purchases, or website activity.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Transactional Email (API/SMTP)$q$, $q$Reliable delivery infrastructure for system-generated messages like order confirmations, receipts, and password resets.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$SMS & WhatsApp Campaigns$q$, $q$Send SMS and WhatsApp messages alongside email campaigns from the same platform and contact lists.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Built-in CRM$q$, $q$Lightweight contact and deal management tools for sales teams, integrated with marketing contact data.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Live Chat & Shared Inbox$q$, $q$A website chat widget and shared inbox for handling real-time customer conversations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Landing Pages & Signup Forms$q$, $q$No-code page and form builders for capturing leads and growing contact lists.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Segmentation & Contact Management$q$, $q$Dynamic segments based on contact attributes, engagement history, and automation activity, with unlimited contacts on most plans.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Reporting & Analytics$q$, $q$Campaign dashboards covering opens, clicks, bounces, and unsubscribes, plus click heatmaps for deeper engagement insight.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Generous free plan with unlimited contacts stored regardless of list size$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Pricing based primarily on email sending volume rather than contact count, favorable for large lists$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Combines email, SMS, WhatsApp, chat, and CRM in a single platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Solid transactional email API and SMTP relay for developers$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Accessible pricing and interface for small businesses new to marketing automation$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Automation and personalization depth lag behind specialized tools like Klaviyo or ActiveCampaign$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Email design templates and editor are considered less polished than some premium competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Lower-tier and free plans include daily sending limits and Brevo branding$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Support responsiveness can be slower on entry-level and free plans$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Native integration marketplace is smaller than that of larger, longer-established CRM/marketing suites$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Is Brevo the same as Sendinblue?$q$, $q$Yes. Sendinblue rebranded to Brevo in 2023 as the company expanded from email marketing into a broader marketing, sales, and CRM platform.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Does Brevo have a free plan?$q$, $q$Yes, Brevo offers a free-forever plan with unlimited contacts and a daily email sending limit, making it accessible for small businesses and new users.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Is Brevo good for ecommerce businesses?$q$, $q$Brevo works well for ecommerce email and SMS marketing and offers integrations with popular ecommerce platforms, though its automation depth is generally less specialized than dedicated ecommerce marketing tools.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$How does Brevo pricing work?$q$, $q$Most Brevo plans are priced mainly by the number of emails sent per month rather than the number of contacts, so businesses with large but rarely emailed lists can avoid per-contact charges.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Does Brevo support SMS and WhatsApp marketing?$q$, $q$Yes, Brevo supports sending SMS and WhatsApp campaigns alongside email from the same dashboard and contact database.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Ecommerce marketing and transactional emails$q$, $q$Automate abandoned cart reminders, order confirmations, and shipping notifications alongside promotional email campaigns.$q$, $q$Ecommerce store owners and online retailers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Small business email newsletters$q$, $q$Design and send regular newsletters and promotional campaigns using pre-built templates without technical setup.$q$, $q$Small business owners and solopreneurs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Multichannel customer engagement$q$, $q$Combine email, SMS, WhatsApp, and live chat within one platform to reach customers across multiple channels.$q$, $q$Marketing teams at growing businesses$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Developer transactional email infrastructure$q$, $q$Use the API or SMTP relay to send system-triggered emails reliably from web and mobile applications.$q$, $q$Developers and SaaS companies$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Free$q$, $q$$0$q$, NULL, $q$["Unlimited contacts","Daily email sending limit","Email campaign builder and templates","Basic marketing automation","Live chat and CRM basics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Starter$q$, $q$From ~$9/month (varies by email volume)$q$, $q$monthly or annual$q$, $q$["No daily sending cap (monthly volume based)","Email support","Basic A/B testing","No Brevo logo on emails (available on higher tiers)"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Business$q$, $q$From ~$18/month (varies by email volume)$q$, $q$monthly or annual$q$, $q$["Advanced marketing automation","Multi-user access and permissions","A/B testing and send-time optimization","Advanced statistics and reporting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$Enterprise$q$, $q$Custom$q$, NULL, $q$["Dedicated IP and infrastructure options","Advanced security and permissions","Dedicated account/success manager","Custom onboarding and support SLAs"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Brevo, known as Sendinblue until its 2023 rebrand, is a marketing platform founded in Paris in 2012. It started as an email and SMS marketing tool aimed at small and mid-sized businesses and has since grown into a broader all-in-one suite spanning marketing automation, transactional email, live chat, and a built-in CRM.$q$, $q$The rebrand to Brevo reflected the company's shift from a pure email service provider to a fuller customer relationship platform, with messaging, sales, and marketing tools consolidated under one login. It remains best known for its email marketing roots, but the product now competes with both classic email tools like Mailchimp and multichannel platforms that bundle SMS, chat, and CRM together.$q$, $q$One of Brevo's defining traits is its pricing structure: rather than charging strictly by the number of contacts stored, most plans are priced primarily around monthly email sending volume, with unlimited contacts even on entry-level tiers. This has made it a common choice for organizations sitting on large but infrequently emailed contact lists.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$who-brevo-is-for$q$, $q$Who Brevo Is For$q$, 2, ARRAY[$q$Brevo suits small and mid-sized businesses, ecommerce merchants, and lean marketing teams that want email, SMS, and basic CRM functionality in a single tool rather than juggling separate subscriptions. Its free tier and volume-based pricing make it appealing for businesses with sizeable contact databases but moderate sending frequency, since they aren't penalized for list size the way they would be with strictly per-contact pricing models.$q$, $q$It also fits agencies managing multiple client accounts, developers who need a straightforward transactional email API or SMTP relay for order confirmations and password resets, and companies that want to add SMS or WhatsApp campaigns alongside email without adopting a separate messaging vendor. Teams that value an accessible, moderately priced entry point into marketing automation, rather than a highly specialized enterprise stack, tend to get the most out of Brevo.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Brevo is a less natural fit for large enterprises with complex deliverability, compliance, or data-governance requirements that expect the depth of infrastructure and account management found in enterprise-tier email platforms. Organizations that need the most advanced ecommerce-specific automation and behavioral personalization, such as deep product-level browse and purchase triggers, may find dedicated ecommerce marketing platforms more capable out of the box.$q$, $q$Teams that prioritize a highly polished, design-forward email editor and template library, or that rely heavily on a very large, mature third-party app marketplace and native integrations comparable to the biggest CRM ecosystems, may also find Brevo's interface and integration depth more basic than what they're used to. Businesses expecting fast, high-touch human support on lower-priced plans should also weigh Brevo's tiered support model before committing.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Brevo offers a drag-and-drop email campaign builder with pre-built templates, alongside a visual marketing automation workflow editor for setting up triggered emails and SMS based on subscriber behavior, such as signups, purchases, or link clicks. A transactional email API and SMTP relay handle system-generated messages like receipts, shipping notifications, and password resets, and are commonly used by developers integrating Brevo into their own applications.$q$, $q$Beyond email, Brevo supports SMS and WhatsApp campaigns from the same dashboard, a live chat widget with a shared inbox, and simple landing page and signup form builders for lead capture. A built-in, lightweight CRM lets sales teams track contacts and deals without a separate tool, and segmentation features allow campaigns to be targeted using contact attributes, engagement history, and automation-driven tags.$q$, $q$Reporting dashboards cover standard email metrics such as opens, clicks, bounces, and unsubscribes, along with heatmap-style click tracking, and the platform includes options like dedicated sending IPs and A/B testing on higher-tier plans for businesses scaling their sending volume.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('fd2949bf-02b3-4401-a031-61e56f53b753', $q$the-brevo-experience$q$, $q$The Brevo Experience$q$, 2, ARRAY[$q$New users typically find Brevo's dashboard organized around clear top-level sections for campaigns, automation, contacts, and conversations, with setup wizards guiding initial sender verification and contact imports. The email and automation builders use a straightforward drag-and-drop approach, and most core workflows, like sending a first campaign or building a basic automation, can be completed without technical help, which keeps the learning curve manageable for non-technical marketers.$q$, $q$Support and documentation are available through help center articles, email, and chat, with response speed and access to phone support generally improving on higher-tier plans. Developers benefit from reasonably well-documented API and SMTP integration guides, and existing integrations with common ecommerce and CMS platforms, such as WordPress and Shopify, help reduce setup friction for typical marketing use cases.$q$, $q$Overall, the day-to-day experience is functional and consolidated rather than flashy: Brevo trades some of the visual polish and integration breadth of pricier competitors for a simpler, more budget-conscious path to running email, SMS, chat, and basic CRM operations from one account.$q$]::text[], 4);
