INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Corporate charge card with no personal guarantee$q$, $q$Issues corporate cards based on company cash and spending activity rather than a founder's personal credit history or liability.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Real-time spend controls$q$, $q$Set spending limits and policies by employee, department, or vendor, with the ability to adjust in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Virtual cards$q$, $q$Generate single-use or vendor-specific virtual cards to control recurring software subscriptions and one-off purchases.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Automated expense management$q$, $q$Captures receipts and automatically matches them to card transactions, reducing manual expense report work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Bill pay (accounts payable)$q$, $q$Automates vendor bill payments and approval workflows alongside card spend in the same platform.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Travel booking$q$, $q$Lets employees book business travel within company-defined policies, tied to the same spend controls as the card.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Accounting integrations$q$, $q$Syncs transaction and expense data with accounting platforms such as QuickBooks, NetSuite, and Xero.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Employee reimbursements$q$, $q$Handles out-of-pocket employee expense reimbursements alongside corporate card transactions.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Rewards program$q$, $q$Card spend earns rewards points that can be redeemed through Brex's rewards marketplace.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Mobile apps$q$, $q$iOS and Android apps let employees and managers submit receipts, review transactions, and approve expenses on the go.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$No personal guarantee required from founders or executives to get a corporate card$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Combines card issuing, expense management, bill pay, and travel in a single platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Real-time visibility into company-wide spend for finance teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Strong integrations with popular accounting software$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Free entry-level access makes it approachable for early-stage startups$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Primarily built for US-incorporated companies, limiting fit for international businesses$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Card limits are tied to company cash balance rather than a traditional credit line, which can fluctuate$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Advanced spend management features may require contacting sales for custom pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Less suited to sole proprietors or very small businesses without significant cash reserves$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Businesses wanting a simple, single-purpose expense tool may find the broader platform more than they need$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$What is Brex?$q$, $q$Brex is a US fintech company that provides corporate charge cards and a spend management platform, including expense management, bill pay, and travel booking, aimed primarily at startups and growing businesses.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Does Brex require a personal guarantee?$q$, $q$No. Brex issues its corporate card based on a company's cash balance and spending activity rather than requiring a founder or executive to personally guarantee the debt.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$How much does Brex cost?$q$, $q$Brex offers a free entry-level plan for its card and basic platform features, with paid, higher tiers of its spend management platform typically requiring contacting sales for pricing based on company needs.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$What size companies use Brex?$q$, $q$Brex is most commonly used by venture-backed startups and scaling technology companies, though its platform is also used by larger growing businesses that need consolidated card, expense, and bill pay management.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Does Brex integrate with accounting software?$q$, $q$Yes, Brex integrates with common accounting platforms such as QuickBooks, NetSuite, and Xero to sync transaction and expense data automatically.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Issuing corporate cards without personal liability$q$, $q$Startups can issue employee cards without a founder personally guaranteeing the company's card debt.$q$, $q$Startup founders and finance leads$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Automating expense reporting$q$, $q$Finance teams reduce manual work by having receipts automatically captured and matched to card transactions.$q$, $q$Finance and accounting teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Managing business travel within policy$q$, $q$Companies book and manage employee travel under the same spend policies used for card transactions.$q$, $q$Operations and travel administrators$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Automating accounts payable$q$, $q$Teams handle vendor bill approvals and payments through Brex's bill pay tools instead of manual check runs.$q$, $q$Accounts payable and finance teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Free / Essentials$q$, $q$Free$q$, NULL, $q$["Corporate charge card with no personal guarantee","Basic expense management and receipt capture","Mobile app access","Core reporting dashboard"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Premium$q$, $q$Contact sales$q$, NULL, $q$["Advanced expense policies and controls","Travel booking","Bill pay / accounts payable automation","Deeper accounting integrations"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$Enterprise$q$, $q$Contact sales$q$, NULL, $q$["Custom integrations","Dedicated account management","Advanced spend controls and reporting","Tailored onboarding and support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Brex is a financial technology company founded in 2017 by Henrique Dubugras and Pedro Franceschi, headquartered in San Francisco, California. It began as a corporate charge card built specifically for startups — companies that traditional banks often turned away because their founders had no personal credit history to lean on or couldn't offer a personal guarantee. Instead of underwriting based on a founder's personal credit, Brex evaluates a company's cash balance and spending behavior, letting newly funded businesses get a card quickly without putting a founder personally on the hook for the company's debt.$q$, $q$Over time, Brex evolved from a single card product into a broader spend management platform, often referred to as Brex Empower. The platform bundles the corporate card with expense management, bill pay (accounts payable automation), travel booking, and accounting-system integrations, aiming to give finance and accounting teams a single system for issuing cards, enforcing spending policies, collecting receipts, and closing the books — rather than requiring separate tools for cards, expenses, and travel.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$who-is-brex-for$q$, $q$Who Brex Is For$q$, 2, ARRAY[$q$Brex is built primarily for venture-backed startups and scaling technology companies that need a corporate card and spend controls in place quickly, without a founder assuming personal liability. Its underwriting model — based on company funds rather than personal credit — makes it a natural fit for newly incorporated businesses that hold cash in a bank or investment account but lack an established credit history.$q$, $q$It also serves finance and accounting teams at growing mid-market companies who want to consolidate card issuing, employee expense reports, vendor bill payments, and travel policy enforcement into one dashboard. Teams that already use accounting software like QuickBooks, NetSuite, or Xero, and want their card and expense data to flow into those systems automatically, are a core part of Brex's target audience.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Brex is primarily designed for US-incorporated companies, so businesses operating outside the US, or without a US entity and US bank account, are generally not a good fit. Sole proprietors and very early-stage businesses without meaningful cash reserves may also struggle to qualify, since Brex's charge card is tied to a company's available funds rather than a conventional revolving line of credit.$q$, $q$Companies looking for a simple, no-frills expense tracking app with a flat, transparent monthly price may find Brex's model less straightforward, since some of its more advanced spend-management features sit behind higher tiers that require contacting sales for pricing. Businesses that just need basic receipt tracking for a handful of employees may find lighter-weight, purely software expense tools a simpler match.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Brex offers a corporate charge card issued without requiring a personal guarantee from founders or executives, paired with real-time spend controls that let finance teams set budgets and limits by employee, department, or vendor. Virtual cards can be generated for specific use cases, such as software subscriptions or one-off vendor payments, giving teams more granular control over where company money goes.$q$, $q$The platform also includes automated expense management with receipt capture and matching, employee reimbursements, and bill pay tools for handling accounts payable workflows. A built-in travel booking product lets companies manage business travel within the same policies used for card spend, and Brex integrates with popular accounting platforms so transaction data can sync automatically instead of requiring manual entry.$q$, $q$Rounding out the platform, Brex offers a rewards program tied to card spend, mobile apps for managing cards and approvals on the go, and reporting dashboards that give finance leaders visibility into company-wide spend in real time.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', $q$the-brex-experience$q$, $q$The Brex Experience$q$, 2, ARRAY[$q$Using Brex typically starts with connecting a company bank account and setting up cardholders, after which employees receive physical or virtual cards tied to policies the finance team configures. The web dashboard is the primary hub for approving expenses, reviewing spend by category, and managing bill payments, while the mobile app lets employees snap photos of receipts and submit expenses from their phones.$q$, $q$Because Brex ties spending limits to real-time company cash rather than a traditional credit check, changes in available funds can affect card limits, which is a meaningful difference from conventional business credit cards. Support and onboarding are generally handled digitally, with self-serve setup for smaller teams and more hands-on sales and support engagement for companies evaluating higher-tier plans or custom integrations.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('90a5952e-cd43-4cf5-bc88-317304be7a50', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
